const https = require('https');
const urlMod = require('url');
function httpReq(method, rawUrl, headers, postBody) {
  return new Promise((resolve, reject) => {
    const parsed = urlMod.parse(rawUrl);
    const opts = { hostname: parsed.hostname, path: parsed.path, method: method, headers: headers || {} };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        let json = null;
        try { json = JSON.parse(body); } catch(e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: json, text: body });
      });
    });
    req.on('error', reject);
    if (postBody) req.write(typeof postBody === 'string' ? postBody : JSON.stringify(postBody));
    req.end();
  });
}

// Material Order: creates ClickUp task when material order is placed
const GHL_TOKEN = '{{ghl_token}}';
const CLICKUP_TOKEN = '{{clickup_token}}';
const MATERIAL_LIST_ID = '{{clickup_list_current_pipeline}}';
const GHL_BASE = 'https://services.leadconnectorhq.com';
const CU_BASE = 'https://api.clickup.com/api/v2';
const GHL_HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };
const CU_HEADERS = { 'Authorization': CLICKUP_TOKEN, 'Content-Type': 'application/json' };

const body = $input.first().json;
const oppId = body.opportunity_id || body.id;
if (!oppId) return [{ json: { status: 'error', message: 'No opportunity ID' } }];

// Get opportunity details
const resp = await httpReq('GET', `${GHL_BASE}/opportunities/${oppId}`, GHL_HEADERS );
const opp = await resp.json;
const fields = opp.customFields || [];
const sku = (fields.find(f => f.id === '{{ghl_cf_material_sku}}'))?.value || 'Unknown SKU';
const orderTotal = (fields.find(f => f.id === '{{ghl_cf_material_order_total}}'))?.value || '0';

// Create ClickUp task
const task = await fetch(`${CU_BASE}/list/${MATERIAL_LIST_ID}/task`, {
  method: 'POST',
  headers: CU_HEADERS,
  body: JSON.stringify({
    name: `Material Order: ${opp.name || oppId}`,
    description: `SKU: ${sku}\nOrder Total: $${orderTotal}\nGHL Opportunity: ${oppId}`,
    status: 'Open',
    priority: 2
  })
});
const taskData = await task.json;

return [{ json: { status: 'ok', opportunity_id: oppId, clickup_task_id: taskData.id, sku, order_total: orderTotal } }];
